/***************************************************************
 * 文件名: voice_module.h
 * 说    明: 语音识别模块 — UART2 指令解析 — 声明
 *           voice_uart_thread: 优先级 24, 栈 8KB
 *           UART2 (PB2=TX, PB3=RX), 115200bps, 8N1
 *           支持 9 种指令: 温度/湿度/时间/日期查询, 喂食/逗猫/风扇控制
 *           使用累积缓冲区解决粘包/半包问题
 ***************************************************************/

#ifndef _VOICE_MODULE_H_
#define _VOICE_MODULE_H_

/***************************************************************
 * 线程函数: voice_uart_thread
 * 说    明: 语音模块 UART 指令解析线程入口
 *           初始化 UART2, 循环接收二进制指令, 查询类直接 UART 回复,
 *           动作类推入命令队列由 lcd_ui 主循环统一执行
 * 参    数:
 *       @arg: 未使用
 ***************************************************************/
void voice_uart_thread(void *arg);

#endif /* _VOICE_MODULE_H_ */
